5: 
6: import (
7: 	"errors"
8: 	"fmt"
9: 	"log/slog"
10: 	"os"
11: 	"strings"
12: 
13: 	"github.com/cilium/ebpf"
14: 	"github.com/cilium/ebpf/asm"
15: 	"github.com/cilium/ebpf/btf"
16: 
17: 	"github.com/cilium/cilium/pkg/datapath/config"
18: 	"github.com/cilium/cilium/pkg/logging/logfields"
19: )
20: 
21: const (
22: 	callsMap = "cilium_calls"
23: )
24: 
25: // LoadCollectionSpec loads the eBPF ELF at the given path and parses it into a
26: // CollectionSpec. This spec is only a blueprint of the contents of the ELF and
27: // does not represent any live resources that have been loaded into the kernel.
28: //
29: // This is a wrapper around ebpf.LoadCollectionSpec that populates the object's
30: // calls map with programs marked with the __declare_tail() annotation. It
31: // performs static reachability analysis of tail call programs. Any unreachable
32: // tail call program is removed from the spec.
33: func LoadCollectionSpec(logger *slog.Logger, path string) (*ebpf.CollectionSpec, error) {
34: 	spec, err := ebpf.LoadCollectionSpec(path)
35: 	if err != nil {
36: 		return nil, err
37: 	}
38: 
39: 	if err := checkUnspecifiedPrograms(spec); err != nil {
40: 		return nil, fmt.Errorf("checking for unspecified programs: %w", err)
41: 	}
42: 
43: 	if err := removeUnreachableTailcalls(logger, spec); err != nil {
44: 		return nil, fmt.Errorf("removing unreachable tail calls: %w", err)
45: 	}
46: 
47: 	if err := resolveTailCalls(spec); err != nil {
48: 		return nil, fmt.Errorf("resolving tail calls: %w", err)
49: 	}
50: 
51: 	return spec, nil
52: }
53: 
54: // checkUnspecifiedPrograms returns an error if any of the programs in the spec
55: // are of the UnspecifiedProgram type.
56: func checkUnspecifiedPrograms(spec *ebpf.CollectionSpec) error {
57: 	for _, prog := range spec.Programs {
58: 		if prog.Type == ebpf.UnspecifiedProgram {
59: 			return fmt.Errorf("program %s has unspecified type: annotate with __section_entry or __declare_tail()", prog.Name)
60: 		}
61: 	}
62: 	return nil
63: }
64: 
65: // isEntrypoint returns true if the program is marked with the __section_entry
66: // annotation.
67: func isEntrypoint(prog *ebpf.ProgramSpec) bool {
68: 	return strings.HasSuffix(prog.SectionName, "/entry")
69: }
70: 
71: // isTailCall returns true if the program is marked with the __declare_tail()
72: // annotation.
73: func isTailCall(prog *ebpf.ProgramSpec) bool {
74: 	return strings.HasSuffix(prog.SectionName, "/tail")
75: }
76: 
77: // tailCallSlot returns the tail call slot for the given program, which must be
78: // marked with the __declare_tail() annotation. The slot is the index in the
79: // calls map that the program will be called from.
80: func tailCallSlot(prog *ebpf.ProgramSpec) (uint32, error) {
81: 	if !isTailCall(prog) {
82: 		return 0, fmt.Errorf("program %s is not a tail call", prog.Name)
83: 	}
84: 
85: 	fn := btf.FuncMetadata(&prog.Instructions[0])
86: 	if fn == nil {
87: 		return 0, fmt.Errorf("program %s has no function metadata", prog.Name)
88: 	}
89: 
90: 	for _, tag := range fn.Tags {
91: 		var slot uint32
92: 		if _, err := fmt.Sscanf(tag, fmt.Sprintf("tail:%s/%%v", callsMap), &slot); err == nil {
93: 			return slot, nil
94: 		}
95: 	}
96: 
97: 	return 0, fmt.Errorf("program %s has no tail call slot", prog.Name)
98: }
99: 
100: // resolveTailCalls populates the calls map with Programs marked with the
101: // __declare_tail annotation.
102: func resolveTailCalls(spec *ebpf.CollectionSpec) error {
103: 	// If cilium_calls map is missing, do nothing.
104: 	ms := spec.Maps[callsMap]
105: 	if ms == nil {
106: 		return nil
107: 	}
108: 
109: 	if ms.Type != ebpf.ProgramArray {
110: 		return fmt.Errorf("%s is not a program array, got %s", callsMap, ms.Type)
111: 	}
112: 
113: 	slots := make(map[uint32]struct{})
114: 	for name, prog := range spec.Programs {
115: 		if !isTailCall(prog) {
116: 			continue
117: 		}
118: 
119: 		slot, err := tailCallSlot(prog)
120: 		if err != nil {
121: 			return fmt.Errorf("getting tail call slot: %w", err)
122: 		}
123: 
124: 		if _, ok := slots[slot]; ok {
125: 			return fmt.Errorf("duplicate tail call slot %d", slot)
126: 		}
127: 		slots[slot] = struct{}{}
128: 
129: 		ms.Contents = append(ms.Contents, ebpf.MapKV{Key: slot, Value: name})
130: 	}
131: 
132: 	return nil
133: }
134: 
135: // removeUnreachableTailcalls removes tail calls that are not reachable from
136: // entrypoint programs. This is done by traversing the call graph of the
137: // entrypoint programs and marking all reachable tail calls. Any tail call that
138: // is not marked is removed from the CollectionSpec.
139: func removeUnreachableTailcalls(logger *slog.Logger, spec *ebpf.CollectionSpec) error {
140: 	type tail struct {
141: 		referenced bool
142: 		visited    bool
143: 		spec       *ebpf.ProgramSpec
144: 	}
145: 
146: 	// Build a map of entrypoint programs annotated with __section_entry.
147: 	entrypoints := make(map[string]*ebpf.ProgramSpec)
148: 	for _, prog := range spec.Programs {
149: 		if isEntrypoint(prog) {
150: 			entrypoints[prog.Name] = prog
151: 		}
152: 	}
153: 
154: 	// Build a map of tail call slots to ProgramSpecs.
155: 	tailcalls := make(map[uint32]*tail)
156: 	for _, prog := range spec.Programs {
157: 		if !isTailCall(prog) {
158: 			continue
159: 		}
160: 
161: 		slot, err := tailCallSlot(prog)
162: 		if err != nil {
163: 			return fmt.Errorf("getting tail call slot: %w", err)
164: 		}
165: 
166: 		tailcalls[slot] = &tail{
167: 			spec: prog,
168: 		}
169: 	}
170: 
171: 	// Discover all tailcalls that are reachable from the given program.
172: 	visit := func(prog *ebpf.ProgramSpec, tailcalls map[uint32]*tail) error {
173: 		// We look back from any tailcall, so we expect there to always be 3 instructions ahead of any tail call instr.
174: 		for i := 3; i < len(prog.Instructions); i++ {
175: 			// The `tail_call_static` C function is always used to call tail calls when
176: 			// the map index is known at compile time.
177: 			// Due to inline ASM this generates the following instructions:
178: 			//   Mov R1, Rx
179: 			//   Mov R2, <map>
180: 			//   Mov R3, <index>
181: 			//   call tail_call
182: 
183: 			// Find the tail call instruction.
184: 			inst := prog.Instructions[i]
185: 			if !inst.IsBuiltinCall() || inst.Constant != int64(asm.FnTailCall) {
186: 				continue
187: 			}
188: 
189: 			// Check that the previous instruction is a mov of the tail call index.
190: 			movIdx := prog.Instructions[i-1]
191: 			if movIdx.OpCode.ALUOp() != asm.Mov || movIdx.Dst != asm.R3 {
192: 				continue
193: 			}
194: 
195: 			// Check that the instruction before that is the load of the tail call map.
196: 			movR2 := prog.Instructions[i-2]
197: 			if movR2.OpCode != asm.LoadImmOp(asm.DWord) || movR2.Src != asm.PseudoMapFD {
198: 				continue
199: 			}
200: 
201: 			ref := movR2.Reference()
202: 
203: 			// Ignore static tail calls made to maps that are not the calls map
204: 			if ref != callsMap {
205: 				logger.Debug(
206: 					"skipping tail call into map other than the calls map",
207: 					logfields.Section, prog.SectionName,
208: 					logfields.Prog, prog.Name,
209: 					logfields.Instruction, i,
210: 					logfields.Reference, ref,
211: 				)
212: 				continue
213: 			}
214: 
215: 			tc := tailcalls[uint32(movIdx.Constant)]
216: 			if tc == nil {
217: 				return fmt.Errorf(
218: 					"potential missed tail call in program %s to slot %d at insn %d",
219: 					prog.Name,
220: 					movIdx.Constant,
221: 					i,
222: 				)
223: 			}
224: 
225: 			tc.referenced = true
226: 		}
227: 
228: 		return nil
229: 	}
230: 
231: 	// Discover all tailcalls that are reachable from the entrypoints.
232: 	for _, prog := range entrypoints {
233: 		if err := visit(prog, tailcalls); err != nil {
234: 			return err
235: 		}
236: 	}
237: 
238: 	// Keep visiting tailcalls until no more are discovered.
239: reset:
240: 	for _, tailcall := range tailcalls {
241: 		// If a tailcall is referenced by an entrypoint or another tailcall we should visit it
242: 		if tailcall.referenced && !tailcall.visited {
243: 			if err := visit(tailcall.spec, tailcalls); err != nil {
244: 				return err
245: 			}
246: 			tailcall.visited = true
247: 
248: 			// Visiting this tail call might have caused tail calls earlier in the list to become referenced, but this
249: 			// loop already skipped them. So reset the loop. If we already visited a tailcall we will ignore them anyway.
250: 			goto reset
251: 		}
252: 	}
253: 
254: 	// Remove all tailcalls that are not referenced.
255: 	for _, tailcall := range tailcalls {
256: 		if !tailcall.referenced {
257: 			logger.Debug(
258: 				"unreferenced tail call, deleting",
259: 				logfields.Section, tailcall.spec.SectionName,
260: 				logfields.Prog, tailcall.spec.Name,
261: 			)
262: 
263: 			delete(spec.Programs, tailcall.spec.Name)
264: 		}
265: 	}
266: 
267: 	return nil
268: }
