270: // LoadAndAssign loads spec into the kernel and assigns the requested eBPF
271: // objects to the given object. It is a wrapper around [LoadCollection]. See its
272: // documentation for more details on the loading process.
273: func LoadAndAssign(logger *slog.Logger, to any, spec *ebpf.CollectionSpec, opts *CollectionOptions) (func() error, error) {
274: 	coll, commit, err := LoadCollection(logger, spec, opts)
275: 	var ve *ebpf.VerifierError
276: 	if errors.As(err, &ve) {
277: 		if _, err := fmt.Fprintf(os.Stderr, "Verifier error: %s\nVerifier log: %+v\n", err, ve); err != nil {
278: 			return nil, fmt.Errorf("writing verifier log to stderr: %w", err)
279: 		}
280: 	}
281: 	if err != nil {
282: 		return nil, fmt.Errorf("loading eBPF collection into the kernel: %w", err)
283: 	}
284: 
285: 	if err := coll.Assign(to); err != nil {
286: 		return nil, fmt.Errorf("assigning eBPF objects to %T: %w", to, err)
287: 	}
288: 
289: 	return commit, nil
290: }
