292: type CollectionOptions struct {
293: 	ebpf.CollectionOptions
294: 
295: 	// Replacements for datapath runtime configs declared using DECLARE_CONFIG.
296: 	// Pass a pointer to a populated object from pkg/datapath/config.
297: 	Constants any
298: 
299: 	// Maps to be renamed during loading. Key is the key in CollectionSpec.Maps,
300: 	// value is the new name.
301: 	MapRenames map[string]string
302: }
303: 
304: // LoadCollection loads the given spec into the kernel with the specified opts.
305: // Returns a function that must be called after the Collection's entrypoints are
306: // attached to their respective kernel hooks. This function commits pending map
307: // pins to the bpf file system for maps that were found to be incompatible with
308: // their pinned counterparts, or for maps with certain flags that modify the
309: // default pinning behaviour.
310: //
311: // When attaching multiple programs from the same ELF in a loop, the returned
312: // function should only be run after all entrypoints have been attached. For
313: // example, attach both bpf_host.c:cil_to_netdev and cil_from_netdev before
314: // invoking the returned function, otherwise missing tail calls will occur.
315: //
316: // The value given in ProgramOptions.LogSize is used as the starting point for
317: // sizing the verifier's log buffer and defaults to 4MiB. On each retry, the log
318: // buffer quadruples in size, for a total of 5 attempts. If that proves
319: // insufficient, a truncated ebpf.VerifierError is returned.
320: //
321: // Any maps marked as pinned in the spec are automatically loaded from the path
322: // given in opts.Maps.PinPath and will be used instead of creating new ones.
323: func LoadCollection(logger *slog.Logger, spec *ebpf.CollectionSpec, opts *CollectionOptions) (*ebpf.Collection, func() error, error) {
324: 	if spec == nil {
325: 		return nil, nil, errors.New("can't load nil CollectionSpec")
326: 	}
327: 
328: 	if opts == nil {
329: 		opts = &CollectionOptions{}
330: 	}
331: 
332: 	logger.Debug("Loading Collection into kernel",
333: 		logfields.MapRenames, opts.MapRenames,
334: 		logfields.Constants, fmt.Sprintf("%#v", opts.Constants),
335: 	)
336: 
337: 	// Copy spec so the modifications below don't affect the input parameter,
338: 	// allowing the spec to be safely re-used by the caller.
339: 	spec = spec.Copy()
340: 
341: 	if err := renameMaps(spec, opts.MapRenames); err != nil {
342: 		return nil, nil, err
343: 	}
344: 
345: 	if err := applyConstants(spec, opts.Constants); err != nil {
346: 		return nil, nil, fmt.Errorf("applying variable overrides: %w", err)
347: 	}
348: 
349: 	// Find and strip all CILIUM_PIN_REPLACE pinning flags before creating the
350: 	// Collection. ebpf-go will reject maps with pins it doesn't recognize.
351: 	toReplace := consumePinReplace(spec)
352: 
353: 	// Attempt to load the Collection.
354: 	coll, err := ebpf.NewCollectionWithOptions(spec, opts.CollectionOptions)
355: 
356: 	// Collect key names of maps that are not compatible with their pinned
357: 	// counterparts and remove their pinning flags.
358: 	if errors.Is(err, ebpf.ErrMapIncompatible) {
359: 		var incompatible []string
360: 		incompatible, err = incompatibleMaps(spec, opts.CollectionOptions)
361: 		if err != nil {
362: 			return nil, nil, fmt.Errorf("finding incompatible maps: %w", err)
363: 		}
364: 		toReplace = append(toReplace, incompatible...)
365: 
366: 		// Retry loading the Collection with necessary pinning flags removed.
367: 		coll, err = ebpf.NewCollectionWithOptions(spec, opts.CollectionOptions)
368: 	}
369: 
370: 	if err != nil {
371: 		return nil, nil, err
372: 	}
373: 
374: 	// Collect Maps that need their bpffs pins replaced. Pull out Map objects
375: 	// before returning the Collection, since commit() still needs to work when
376: 	// the Map is removed from the Collection, e.g. by [ebpf.Collection.Assign].
377: 	pins, err := mapsToReplace(toReplace, spec, coll, opts.CollectionOptions)
378: 	if err != nil {
379: 		return nil, nil, fmt.Errorf("collecting map pins to replace: %w", err)
380: 	}
381: 
382: 	// Load successful, return a function that must be invoked after attaching the
383: 	// Collection's entrypoint programs to their respective hooks.
384: 	commit := func() error {
385: 		return commitMapPins(logger, pins)
386: 	}
387: 	return coll, commit, nil
388: }
389: 
390: // renameMaps applies renames to coll.
391: func renameMaps(coll *ebpf.CollectionSpec, renames map[string]string) error {
392: 	for name, rename := range renames {
393: 		mapSpec := coll.Maps[name]
394: 		if mapSpec == nil {
395: 			return fmt.Errorf("unknown map %q: can't rename to %q", name, rename)
396: 		}
397: 
398: 		mapSpec.Name = rename
399: 	}
400: 
401: 	return nil
402: }
403: 
404: // applyConstants sets the values of BPF C runtime configurables defined using
405: // the DECLARE_CONFIG macro.
406: func applyConstants(spec *ebpf.CollectionSpec, obj any) error {
407: 	if obj == nil {
408: 		return nil
409: 	}
410: 
411: 	constants, err := config.StructToMap(obj)
412: 	if err != nil {
413: 		return fmt.Errorf("converting struct to map: %w", err)
414: 	}
415: 
416: 	for name, value := range constants {
417: 		constName := config.ConstantPrefix + name
418: 
419: 		v, ok := spec.Variables[constName]
420: 		if !ok {
421: 			return fmt.Errorf("can't set non-existent Variable %s", name)
422: 		}
423: 
424: 		if v.MapName() != config.Section {
425: 			return fmt.Errorf("can only set Cilium config variables in section %s (got %s:%s), ", config.Section, v.MapName(), name)
426: 		}
427: 
428: 		if err := v.Set(value); err != nil {
429: 			return fmt.Errorf("setting Variable %s: %w", name, err)
430: 		}
431: 	}
432: 
433: 	return nil
434: }
