16: 	"github.com/cilium/statedb/reconciler"
17: 	"k8s.io/apimachinery/pkg/util/sets"
18: )
19: 
20: // ErrMapNotOpened is returned when the MapOps is used with a BPF map that is not open yet.
21: // In general this should be avoided and the map should be opened in a start hook before
22: // the reconciler. If the map won't be used then the reconciler should not be started.
23: var ErrMapNotOpened = errors.New("BPF map has not been opened")
24: 
25: // KeyValue is the interface that an BPF map value object must implement.
26: //
27: // The object can either store the key and value directly in struct form
28: // and use StructBinaryMarshaler{}, or it can implement conversion to binary
29: // form on the fly by implementing BinaryMarshaler by hand.
30: type KeyValue interface {
31: 	BinaryKey() encoding.BinaryMarshaler
32: 	BinaryValue() encoding.BinaryMarshaler
33: }
34: 
35: // StructBinaryMarshaler implements a BinaryMarshaler for a struct of
36: // primitive fields. Same caviats apply as with cilium/ebpf when using a
37: // struct as key or value.
38: // Example usage:
39: //
40: //	func (x *X) Key() encoding.BinaryMarshaler {
41: //	  return StructBinaryMarshaler{x}
42: //	}
43: type StructBinaryMarshaler struct {
44: 	Target any // pointer to struct
45: }
46: 
47: func (m StructBinaryMarshaler) MarshalBinary() ([]byte, error) {
48: 	v := reflect.ValueOf(m.Target)
49: 	size := int(v.Type().Elem().Size())
50: 	return unsafe.Slice((*byte)(v.UnsafePointer()), size), nil
51: }
52: 
53: type mapOps[KV KeyValue] struct {
54: 	m *Map
55: }
56: 
57: func NewMapOps[KV KeyValue](m *Map) reconciler.Operations[KV] {
58: 	ops := &mapOps[KV]{m}
59: 	return ops
60: }
61: 
62: func (ops *mapOps[KV]) withMap(do func(m *ebpf.Map) error) error {
63: 	ops.m.lock.RLock()
64: 	defer ops.m.lock.RUnlock()
65: 	if ops.m.m == nil {
66: 		return ErrMapNotOpened
67: 	}
68: 	return do(ops.m.m)
69: }
70: 
71: // Delete implements reconciler.Operations.
72: func (ops *mapOps[KV]) Delete(ctx context.Context, txn statedb.ReadTxn, _ statedb.Revision, entry KV) error {
73: 	return ops.withMap(func(m *ebpf.Map) error {
74: 		err := ops.m.m.Delete(entry.BinaryKey())
75: 		if errors.Is(err, ebpf.ErrKeyNotExist) {
76: 			// Silently ignore deletions of non-existing keys.
77: 			return nil
78: 		}
79: 		return err
80: 	})
81: }
82: 
83: type keyIterator struct {
84: 	m          *ebpf.Map
85: 	nextKey    []byte
86: 	err        error
87: 	maxEntries uint32
88: }
89: 
90: func (it *keyIterator) Err() error {
91: 	return it.err
92: }
93: 
94: func (it *keyIterator) Next() []byte {
95: 	if it.maxEntries == 0 {
96: 		return nil
97: 	}
98: 	var key []byte
99: 	if it.nextKey == nil {
100: 		key, it.err = it.m.NextKeyBytes(nil)
101: 	} else {
102: 		key, it.err = it.m.NextKeyBytes(it.nextKey)
103: 	}
104: 	if key == nil || it.err != nil {
105: 		return nil
106: 	}
107: 	it.nextKey = key
108: 	it.maxEntries--
109: 	return key
110: }
111: 
112: func (ops *mapOps[KV]) toStringKey(kv KV) string {
113: 	key, _ := kv.BinaryKey().MarshalBinary()
114: 	return string(key)
115: }
116: 
117: // Prune BPF map values that do not exist in the table.
118: func (ops *mapOps[KV]) Prune(ctx context.Context, txn statedb.ReadTxn, objs iter.Seq2[KV, statedb.Revision]) error {
119: 	return ops.withMap(func(m *ebpf.Map) error {
120: 		desiredKeys := sets.New[string]()
121: 		for obj := range objs {
122: 			desiredKeys.Insert(ops.toStringKey(obj))
123: 		}
124: 
125: 		// We need to collect the keys to prune first, as it is not safe to
126: 		// delete entries while iterating
127: 		keysToPrune := [][]byte{}
128: 		mapIter := &keyIterator{m, nil, nil, m.MaxEntries()}
129: 		for key := mapIter.Next(); key != nil; key = mapIter.Next() {
130: 			if !desiredKeys.Has(string(key)) {
131: 				keysToPrune = append(keysToPrune, key)
132: 			}
133: 		}
134: 
135: 		var errs []error
136: 		for _, key := range keysToPrune {
137: 			if err := m.Delete(key); err != nil {
138: 				errs = append(errs, err)
139: 			}
140: 		}
141: 
142: 		errs = append(errs, mapIter.Err())
143: 		return errors.Join(errs...)
144: 	})
145: }
146: 
147: // Update the BPF map value to match with the object in the desired state table.
148: func (ops *mapOps[KV]) Update(ctx context.Context, txn statedb.ReadTxn, _ statedb.Revision, entry KV) error {
149: 	return ops.withMap(func(m *ebpf.Map) error {
150: 		return m.Put(entry.BinaryKey(), entry.BinaryValue())
151: 	})
152: }
